const fs = require('fs').promises;

async function readDataFile() {
  try {
    const data = await fs.readFile('data.txt', 'utf8');
    console.log('data.txt content:', data);
  } catch (err) {
    if (err.code === 'ENOENT') {
      console.log('File not found, please create data.txt');
    } else {
      console.error('An unexpected error occurred:', err.message);
      throw err; // rethrow to exit with error
    }
  }
}

async function readConfig() {
  try {
    const configData = await fs.readFile('config.json', 'utf8');
    try {
      const config = JSON.parse(configData);
      console.log('Config:', config);
    } catch (parseErr) {
      console.error('config.json contains invalid JSON');
    }
  } catch (err) {
    if (err.code === 'ENOENT') {
      console.log('config.json not found, using defaults');
    } else {
      console.error('Error reading config:', err.message);
    }
  }
}

(async () => {
  await readDataFile();
  await readConfig();
})();
